WebLink.url:
{!REQUIRESCRIPT('/soap/ajax/47.0/connection.js')}
{!REQUIRESCRIPT('/soap/ajax/47.0/apex.js')}

if('{!Human__c.Status__c}' == '受付'){
var id = '{!Human__c.Id}';

var result = sforce.apex.execute('SFTR_O_HumanWebService','sendMendan',{itemId:id});

if (result == '研修省略'){
alert('登録前研修会は省略しました');
location.reload();
} else if(result == '研修通知'){
alert('登録前研修会は通知しました');
location.reload();
} else {
alert('登録前研修会の通知が失敗しました');
}

} else {
//ステータス＝受付以外の場合
alert('この処理は実行できません。');
}
